#include <stdio.h>

int main() {
    int feet;
    int inches;
    double total_inches;
    double centimeters;

    // Read feet and inches from stdin
    scanf("%d %d", &feet, &inches);

    // Convert feet to inches and add to existing inches
    total_inches = (double)feet * 12.0 + inches;

    // Convert total inches to centimeters
    centimeters = total_inches * 2.54;

    // Print the result formatted to two decimal places
    printf("Total Centimeters: %.2f\n", centimeters);

    return 0;
}

#include <stdio.h>

int main() {
    int total_seconds;
    int hours;
    int minutes;
    int seconds;

    // Read total seconds from stdin
    scanf("%d", &total_seconds);

    // Calculate hours
    hours = total_seconds / 3600;

    // Calculate remaining seconds after extracting hours
    total_seconds = total_seconds % 3600;

    // Calculate minutes from remaining seconds
    minutes = total_seconds / 60;

    // Calculate remaining seconds after extracting minutes
    seconds = total_seconds % 60;

    // Print the result
    printf("Hours: %d, Minutes: %d, Seconds: %d\n", hours, minutes, seconds);

    return 0;
}

#include <stdio.h>

int main() {
    double principal;
    double rate;
    int time;
    double simple_interest;

    // Read principal, rate, and time from stdin
    scanf("%lf %lf %d", &principal, &rate, &time);

    // Calculate simple interest: P * R * T
    simple_interest = principal * rate * time;

    // Print the result formatted to two decimal places
    printf("Simple Interest: %.2f\n", simple_interest);

    return 0;
}

#include <stdio.h>

int main() {
    int num1;
    int num2;

    // Read two integers from stdin
    scanf("%d %d", &num1, &num2);

    // Swap using arithmetic operations
    num1 = num1 + num2; // num1 now holds the sum of original num1 and num2
    num2 = num1 - num2; // num2 now holds original num1 (sum - original num2)
    num1 = num1 - num2; // num1 now holds original num2 (sum - new num2 which is original num1)

    // Print the swapped values
    printf("Swapped values: %d %d\n", num1, num2);

    return 0;
}

#include <stdio.h>

int main() {
    double celsius;
    double fahrenheit;
    double kelvin;

    // Read Celsius temperature from stdin
    scanf("%lf", &celsius);

    // Calculate Fahrenheit temperature
    fahrenheit = (celsius * 9.0 / 5.0) + 32.0;

    // Calculate Kelvin temperature
    kelvin = celsius + 273.15;

    // Print the results formatted to two decimal places
    printf("Fahrenheit: %.2f\n", fahrenheit);
    printf("Kelvin: %.2f\n", kelvin);

    return 0;
}

#include <stdio.h>

int main() {
    int score1, weight1;
    int score2, weight2;
    int score3, weight3;
    double weighted_average;
    int total_weight;

    // Read scores and weights from stdin
    scanf("%d %d %d %d %d %d", &score1, &weight1, &score2, &weight2, &score3, &weight3);

    // Calculate the sum of (score * weight)
    double weighted_sum = (double)(score1 * weight1) + (score2 * weight2) + (score3 * weight3);

    // Calculate the total weight
    total_weight = weight1 + weight2 + weight3;

    // Calculate the weighted average
    weighted_average = weighted_sum / total_weight;

    // Print the result formatted to two decimal places
    printf("Weighted Average: %.2f\n", weighted_average);

    return 0;
}

#include <stdio.h>

int main() {
    int total_items;
    int num_people;
    int items_per_person;
    int remaining_items;

    // Read total items and number of people from stdin
    scanf("%d %d", &total_items, &num_people);

    // Calculate items each person receives
    items_per_person = total_items / num_people;

    // Calculate remaining items
    remaining_items = total_items % num_people;

    // Print the results
    printf("Items per person: %d\n", items_per_person);
    printf("Remaining items: %d\n", remaining_items);

    return 0;
}

#include <stdio.h>

int main() {
    int number;
    int hundreds_digit;
    int tens_digit;
    int units_digit;

    // Read the 3-digit number from stdin
    scanf("%d", &number);

    // Extract the hundreds digit
    hundreds_digit = number / 100;

    // Extract the tens digit (first remove hundreds, then divide by 10)
    tens_digit = (number % 100) / 10;

    // Extract the units digit
    units_digit = number % 10;

    // Print the extracted digits
    printf("Hundreds digit: %d\n", hundreds_digit);
    printf("Tens digit: %d\n", tens_digit);
    printf("Units digit: %d\n", units_digit);

    return 0;
}

#include <stdio.h>

int main() {
    double initial_odometer;
    double final_odometer;
    double fuel_consumed;
    double miles_driven;
    double mpg;

    // Read initial odometer, final odometer, and fuel consumed from stdin
    scanf("%lf %lf %lf", &initial_odometer, &final_odometer, &fuel_consumed);

    // Calculate total miles driven
    miles_driven = final_odometer - initial_odometer;

    // Calculate Miles Per Gallon (MPG)
    mpg = miles_driven / fuel_consumed;

    // Print the result formatted to two decimal places
    printf("Miles Per Gallon: %.2f\n", mpg);

    return 0;
}

#include <stdio.h>

int main() {
    int item_dollars, item_cents;
    int paid_dollars, paid_cents;
    int item_total_cents;
    int paid_total_cents;
    int change_total_cents;
    int change_dollars;
    int change_cents;

    // Read item price (dollars and cents)
    scanf("%d %d", &item_dollars, &item_cents);

    // Read amount paid (dollars and cents)
    scanf("%d %d", &paid_dollars, &paid_cents);

    // Convert item price to total cents
    item_total_cents = item_dollars * 100 + item_cents;

    // Convert paid amount to total cents
    paid_total_cents = paid_dollars * 100 + paid_cents;

    // Calculate total change in cents
    change_total_cents = paid_total_cents - item_total_cents;

    // Convert total change cents back to dollars and cents
    change_dollars = change_total_cents / 100;
    change_cents = change_total_cents % 100;

    // Print the change
    printf("Change: %d dollars and %d cents\n", change_dollars, change_cents);

    return 0;
}
